def fix_surfaces_filter(scene):
    for view_layer in scene.view_layers:
        view_layer.use_pass_combined = True

def fix_camera(scene):
    cameras = [obj for obj in scene.objects if obj.type == 'CAMERA']
    if cameras:
        scene.camera = cameras[0]
    else:
        raise ValueError('No camera in scene')

def fix_camera_clip(scene):
    if not scene.camera:
        return
    camera = scene.camera.data
    # Auto-calculate bounds
    min_z, max_z = float('inf'), float('-inf')
    for obj in scene.objects:
        if obj.type in ['MESH', 'CURVE', 'ARMATURE']:
            for vertex in obj.data.vertices:
                z = (obj.matrix_world @ vertex.co).z
                min_z = min(min_z, z)
                max_z = max(max_z, z)
    if min_z != float('inf'):
        camera.clip_start = max(0.01, min_z - 10)
        camera.clip_end = max_z + 10

def fix_light_power(scene):
    for light in bpy.data.lights:
        if light.energy == 0:
            light.energy = 1000 if light.type == 'AREA' else 100

def fix_compositor(scene):
    if not scene.use_nodes:
        return
    tree = scene.node_tree
    render_layers_node = next((n for n in tree.nodes if n.type == 'RENDER_LAYERS'), None)
    composite_node = next((n for n in tree.nodes if n.type == 'COMPOSITE'), None)
    if render_layers_node and composite_node:
        tree.links.new(render_layers_node.outputs[0], composite_node.inputs[0])

def unhide_all_objects(scene):
    for obj in scene.objects:
        obj.hide_render = False

def fix_resolution(scene, max_res=4096):
    scene.render.resolution_x = min(scene.render.resolution_x, max_res)
    scene.render.resolution_y = min(scene.render.resolution_y, max_res)
